import{_ as t,o as n,c as r,a}from"./chunks/framework.BHSVNLI7.js";const p=JSON.parse('{"title":"Welcome to PenguinLab","description":"Linux Kernel Learning Station — from QEMU to kernel internals, driver development, and the full embedded Linux stack","frontmatter":{"title":"Welcome to PenguinLab","description":"Linux Kernel Learning Station — from QEMU to kernel internals, driver development, and the full embedded Linux stack"},"headers":[],"relativePath":"en/index.md","filePath":"en/index.md","lastUpdated":null}'),d={name:"en/index.md"};function i(o,e,l,s,c,u){return n(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="welcome-to-penguinlab" tabindex="-1">Welcome to PenguinLab <a class="header-anchor" href="#welcome-to-penguinlab" aria-label="Permalink to &quot;Welcome to PenguinLab&quot;">​</a></h1><blockquote><p>Linux Kernel Learning Station — from QEMU to kernel internals, driver development, and the full embedded Linux stack</p></blockquote><p>PenguinLab is a Linux kernel learning station covering a complete knowledge graph: schedulers, memory management, filesystems, networking stacks, driver development, the full embedded Linux stack, debugging and tuning. All hands-on practice is based on QEMU, supporting ARM32/ARM64/RISC-V/x86_64 architectures.</p><hr><h2 id="learning-paths" tabindex="-1">Learning Paths <a class="header-anchor" href="#learning-paths" aria-label="Permalink to &quot;Learning Paths&quot;">​</a></h2><p>Tutorials are organized by knowledge graph layers. Each tutorial lists prerequisites and follow-up topics — you can follow the recommended path step by step, or pick and choose based on your interests.</p><table tabindex="0"><thead><tr><th>Layer</th><th>Direction</th><th>Content</th></tr></thead><tbody><tr><td>Foundations</td><td>Environment setup → Kernel modules → Data structures → Processes</td><td>Required basics, building the foundation for kernel development</td></tr><tr><td>Kernel Subsystems</td><td>Scheduler / Memory management / Filesystems / Networking</td><td>Diving deep into core kernel internals</td></tr><tr><td>Driver Development</td><td>Character devices → Platform drivers → Device tree → Interrupts</td><td>Mastering mainline kernel driver development</td></tr><tr><td>Embedded Full Stack</td><td>Cross-compilation → Bootloader → Buildroot → BSP</td><td>Complete embedded Linux development workflow</td></tr><tr><td>Debugging &amp; Performance</td><td>printk → ftrace → perf → eBPF</td><td>Full-stack kernel debugging and performance analysis</td></tr><tr><td>Virtualization &amp; Containers</td><td>KVM / Namespaces / cgroups</td><td>Understanding the kernel foundations of virtualization and containers</td></tr></tbody></table><hr><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ul><li><a href="/PenguinLab/booklist">Recommended Books</a></li><li><a href="/PenguinLab/qemu-reference">QEMU ARM Quick Reference</a></li></ul>',10)])])}const h=t(d,[["render",i]]);export{p as __pageData,h as default};
